onClick:
{{
  (async () => {
    try {
      const loginRows = await loginUser.run();
      const user = loginRows?.[0] || loginUser.data?.[0];

      if (!user) {
        showAlert("Wrong username or password", "error");
        return;
      }

      await storeValue("userId", user.user_id);
      await storeValue("username", user.username);
      await storeValue("companyId", user.company_id);
      await storeValue("companyName", user.company_name);
      await storeValue("roleId", user.role_id);
      await storeValue("roleCode", user.role_code);
      await storeValue("roleName", user.role_name);

      const cashRegisterRows = await GetUserCashRegister.run();
      const cashRegister = cashRegisterRows?.[0] || GetUserCashRegister.data?.[0] || {};

      await storeValue("cashRegisterId", cashRegister.cashRegisterId || null);
      await storeValue("cashRegisterCode", cashRegister.cashRegisterCode || "");
      await storeValue("cashRegisterName", cashRegister.cashRegisterName || "");
      await storeValue("warehouseId", cashRegister.warehouseId || null);
      await storeValue("warehouseCode", cashRegister.warehouseCode || "");
      await storeValue("warehouseName", cashRegister.warehouseName || "");

      if (!cashRegister.cashRegisterId) {
        showAlert("No cash register is assigned to this user.", "warning");
      }

      showModal("Warehouse");
    } catch (error) {
      showAlert("Login failed: " + error.message, "error");
      console.log(error);
    }
  })()
}}
